396	    fn render_jsonl_snapshot(&self) -> Result<String, SessionError> {
397	        let mut lines = vec![self.meta_record()?.render()];
398	        if let Some(compaction) = &self.compaction {
399	            lines.push(compaction.to_jsonl_record()?.render());
400	        }
401	        lines.extend(
402	            self.messages
403	                .iter()
404	                .map(|message| message_record(message).render()),
405	        );
406	        let mut rendered = lines.join("\n");
407	        rendered.push('\n');
408	        Ok(rendered)
409	    }
