411	    fn append_persisted_message(&self, message: &ConversationMessage) -> Result<(), SessionError> {
412	        let Some(path) = self.persistence_path() else {
413	            return Ok(());
414	        };
415	
416	        let needs_bootstrap = !path.exists() || fs::metadata(path)?.len() == 0;
417	        if needs_bootstrap {
418	            self.save_to_path(path)?;
419	            return Ok(());
420	        }
421	
422	        let mut file = OpenOptions::new().append(true).open(path)?;
423	        writeln!(file, "{}", message_record(message).render())?;
424	        Ok(())
425	    }
